            return dp[new_visited] = 1;
        }

        // If the current node's label matches the left and right ends
        if (current_char == left_char && current_char == right_char) {
            return dp[new_visited] = 2;
        }

        // Try all neighbors
        long long max_len = 0;
        for (long long neighbor : adj[node]) {
            // Skip if neighbor is already visited
            if (visited & (1 << neighbor)) continue;

            // Check if the current node's label matches the left or right end
            long long len = 0;
            if (current_char == left_char) {
                len = 1 + dfs(neighbor, new_visited, left, neighbor);
            } else if (current_char == right_char) {
                len = 1 + dfs(neighbor, new_visited, neighbor, right);
            } else {
                len = 1 + dfs(neighbor, new_visited, left, right);
