    vector<vector<long long>> adj(n);
    for (auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    // Use bitmask to represent visited nodes
    vector<vector<long long>> dp(1 << n, -1);

    // Initialize dp for single nodes
    for (long long i = 0; i < n; ++i) {
        dp[1 << i] = 1;
    }

    // DFS to find the longest palindrome
    function<long long(long long, long long, long long, long long)> dfs = [&](long long node, long long visited, long long left, long long right) -> long long {
        // If current node is already visited
        if (visited & (1 << node)) {
            return 0;
        }

        // Mark current node as visited
        long long new_visited = visited | (1 << node);

        // Check if the current node's label can be used to form a palindrome
        long long current_char = label[node];
        long long left_char = label[left];
        long long right_char = label[right];

        // If the current node is the middle of the palindrome
        if (left == right) {
            return dp[new_visited] = 1;
        }

        // If the current node's label matches the left and right ends
        if (current_char == left_char && current_char == right_char) {
            return dp[new_visited] = 2;
        }

        // Try all neighbors
        long long max_len = 0;
        for (long long neighbor : adj[node]) {
            // Skip if neighbor is already visited
            if (visited & (1 << neighbor)) continue;

            // Check if the current node's label matches the left or right end
            long long len = 0;
            if (current_char == left_char) {
                len = 1 + dfs(neighbor, new_visited, left, neighbor);
            } else if (current_char == right_char) {
                len = 1 + dfs(neighbor, new_visited, neighbor, right);
            } else {
                len = 1 + dfs(neighbor, new_visited, left, right);
            }

            max_len = max(max_len, len);
        }

        return dp[new_visited] = max_len;
    };

    long long max_palindrome = 0;
    for (long long i = 0; i < n; ++i) {
        long long len = dfs(i, 1 << i, i, i);
        max_palindrome = max(max_palindrome, len);
    }

    return max_palindrome;
}
